# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
import secrets
import smtplib, os

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///test.db'
db = SQLAlchemy(app)

class ResetToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), nullable=False)
    token = db.Column(db.String(120), nullable=False)

db.create_all()

@app.route('/reset-password', methods=['POST'])
def reset_password():
    email = request.json.get('email')
    if not email:
        return jsonify({'message': 'Email is required'}), 400

    token = secrets.token_urlsafe(32)
    reset_entry = ResetToken(email=email, token=token)
    db.session.add(reset_entry)
    db.session.commit()

    reset_link = f"http://example.com/reset?token={token}"
    with smtplib.SMTP('smtp.example.com', 587) as server:
        server.starttls()
        server.login(os.environ.get('EMAIL_USER'), os.environ.get('EMAIL_PASS'))
        server.sendmail(
            os.environ.get('EMAIL_USER'),
            email,
            f"Subject: Password Reset\n\nClick here to reset your password: {reset_link}"
        )

    return jsonify({'message': 'Reset link has been sent.'}), 200

if __name__ == '__main__':
    app.run(debug=True)